  title: string;
  icon?: string;
  route?: string;
  expanded?: boolean;
  isSvg?: boolean;
  children?: MenuItem[];
  isLabel?: boolean;
  /** When `false`, `routerLinkActive` uses prefix match (nested routes under `route`). Default `true`. */
