  getCustomIcons() {
    return this.customIcons;
  }

  toggleSidebar(): void {
    this.sidebarOpenSubject.next(!this.sidebarOpenSubject.value);
  }

  setSidebarState(isOpen: boolean): void {
    this.sidebarOpenSubject.next(isOpen);
  }
